#include <iostream>
using namespace std;
string s;
int k,ans=0 ;
int main()
{
    cin>>s>>k;
    int t=0;
    for(int i=0;i<s.size()-k;i++)
    {
        int minnum=0x3f3f3f3f;
        for(int j=t;j<=k+i;j++)
        {
            if(minnum>s[j]-'0')
            {
                minnum=s[j]-'0';
                t=j+1;
            }
        }
        ans=ans*10+minnum;
    }
    cout<<ans;
    return 0;
}
